import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.jWxB9oXr.js";const m=JSON.parse('{"title":"Why Silvery?","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Why Silvery?"}],["meta",{"property":"og:description","content":"Why Silvery? — an in-depth guide for building terminal apps with Silvery."}],["meta",{"property":"og:url","content":"https://silvery.dev/guide/why-silvery.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/guide/why-silvery.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Guide\\",\\"item\\":\\"https://silvery.dev/guide\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Why Silvery?\\",\\"item\\":\\"https://silvery.dev/guide/why-silvery\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Why Silvery?\\",\\"description\\":\\"Why Silvery? — an in-depth guide for building terminal apps with Silvery.\\",\\"url\\":\\"https://silvery.dev/guide/why-silvery.html\\",\\"dateModified\\":\\"2026-04-10T21:39:01.000Z\\",\\"datePublished\\":\\"2026-04-10T21:39:01.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"guide/why-silvery.md","filePath":"guide/why-silvery.md","lastUpdated":1775857141000}'),o={name:"guide/why-silvery.md"};function n(s,e,l,d,p,h){return a(),i("div",null,[...e[0]||(e[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/why-silvery.md for this page in Markdown format</div><h1 id="why-silvery" tabindex="-1">Why Silvery? <a class="header-anchor" href="#why-silvery" aria-label="Permalink to &quot;Why Silvery?&quot;">​</a></h1><p>Silvery started from a single frustration — <strong>React terminal components can&#39;t know their own size during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a></strong> — and grew into a ground-up reimplementation with a different architectural commitment: <strong>atomic frame rendering</strong>. Every frame is either fully committed to the terminal or not at all. No intermediate states. No flicker. No component dropout on scroll. No half-updated trees.</p><h2 id="the-core-problem" tabindex="-1">The Core Problem <a class="header-anchor" href="#the-core-problem" aria-label="Permalink to &quot;The Core Problem&quot;">​</a></h2><p>In existing React terminal frameworks, React renders components first, then a layout engine (like <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>) calculates positions and sizes. Components <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> at <code>width: 0</code> on the first pass, layout runs, and then components re-<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> with real dimensions. This &quot;two-pass dance&quot; means intermediate states are observable — and when the renderer is interrupted (by React fiber, by the terminal painting mid-emission, by a scroll event triggering re-layout), those broken intermediate states end up on screen.</p><p>You see this in real apps: flicker during streaming. Components appearing and disappearing during scroll. Blank cells in the middle of a layout. The app works fine in demo videos but falls apart under real interaction.</p><p>This has been a <a href="https://github.com/vadimdemedes/ink/issues/5" target="_blank" rel="noreferrer">known limitation</a> in existing frameworks since 2016. Addressing it requires a fundamentally different rendering pipeline — one where layout runs before <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>, and where frame emission commits atomically.</p><h2 id="silvery-s-approach" tabindex="-1">Silvery&#39;s Approach <a class="header-anchor" href="#silvery-s-approach" aria-label="Permalink to &quot;Silvery&#39;s Approach&quot;">​</a></h2><p>Silvery inverts the order: layout runs first, then components <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> with actual dimensions available via <code>useBoxRect()</code>:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">item</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">item</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Item</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useBoxRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">truncate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(item.title, width </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)}&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>No prop drilling, no post-<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> measurement, no <code>width: 0</code> on first paint. This architectural change also unlocks native scrollable containers (<code>overflow=&quot;scroll&quot;</code>) and automatic text truncation -- features that depend on knowing &quot;how much space do I have?&quot;</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>Silvery&#39;s atomic layout-first pipeline + cell-level buffer diff make it <strong>3–27× faster than <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 (typically 15–20×)</strong> in our mounted rerender benchmarks. The <span class="glossary-hint" data-tooltip="Final rendering stage — diffs terminal buffers and emits minimal ANSI escape sequences">output phase</span> emits <strong>10–20× less output</strong> (much more for large trees) to the terminal than <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>&#39;s line-level diff.</p><h3 id="mounted-rerender-throughput" tabindex="-1">Mounted rerender throughput <a class="header-anchor" href="#mounted-rerender-throughput" aria-label="Permalink to &quot;Mounted rerender throughput&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Silvery advantage</th></tr></thead><tbody><tr><td>Cursor move 20-item (all visible)</td><td><strong>2.7×</strong></td></tr><tr><td>Cursor move 100-item</td><td><strong>3.1×</strong></td></tr><tr><td>Kanban move editing marker</td><td><strong>3.3×</strong></td></tr><tr><td>Memo&#39;d cursor highlight 100 (inverse)</td><td><strong>5.3×</strong></td></tr><tr><td>Memo&#39;d cursor highlight 1000 (inverse)</td><td><strong>6.1×</strong></td></tr><tr><td>Memo&#39;d 100-item single toggle</td><td><strong>5.1×</strong></td></tr><tr><td>Memo&#39;d 500-item single toggle</td><td><strong>5.7×</strong></td></tr><tr><td>Memo&#39;d kanban 5×20 move editing marker</td><td><strong>4.3×</strong></td></tr></tbody></table><p><em>Synchronous rerender throughput, mocked stdout. Reproduce: <code>bun run bench</code>. See <a href="/guide/silvery-vs-ink.html#performance-size">detailed benchmarks</a> for methodology.</em></p><h3 id="bundle-size-—-parity-with-ink-yoga" tabindex="-1">Bundle size — parity with Ink+Yoga <a class="header-anchor" href="#bundle-size-—-parity-with-ink-yoga" aria-label="Permalink to &quot;Bundle size — parity with Ink+Yoga&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Package</th><th>Minified + Gzipped</th></tr></thead><tbody><tr><td><a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 + <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> (baseline)</td><td>116.6 KB</td></tr><tr><td><code>silvery/runtime</code> (core + flexily)</td><td><strong>114.9 KB (tied)</strong></td></tr></tbody></table><p>Pure TypeScript, zero <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>, zero native dependencies, instant startup (no async <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> init).</p><h3 id="why-the-speedup" tabindex="-1">Why the speedup <a class="header-anchor" href="#why-the-speedup" aria-label="Permalink to &quot;Why the speedup&quot;">​</a></h3><p>Silvery tracks 7 independent <span class="glossary-hint" data-tooltip="Per-node change tracking — 7 independent flags control which pipeline phases re-execute">dirty flags</span> per node. When a user presses a key, only the nodes that actually changed are re-rendered — React <span class="glossary-hint" data-tooltip="The process of comparing old and new React trees to determine what changed">reconciliation</span>, layout, and content generation are all skipped for unchanged nodes. The cell-level <span class="glossary-hint" data-tooltip="Final rendering stage — diffs terminal buffers and emits minimal ANSI escape sequences">output phase</span> then emits only the cells that differ from the previous frame, using relative cursor positioning to keep the wire size minimal.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><p>Silvery ships 45+ components organized across several categories:</p><p><strong>Layout:</strong> <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>, <a href="/api/spacer" class="hover-link" data-tooltip="Utility component that expands to fill available space — like CSS flex-grow: 1.">Spacer</a>, <a href="/components/Fill" class="hover-link" data-tooltip="Measures available space and passes dimensions to children via render prop">Fill</a>, <a href="/guide/silvery-vs-ink#both-have" class="hover-link" data-tooltip="Utility component that renders a newline character — equivalent to a line break in terminal output.">Newline</a>, <a href="/components/Divider" class="hover-link" data-tooltip="Horizontal line separator with optional title label">Divider</a>, <a href="/components/SplitView" class="hover-link" data-tooltip="Resizable split panes component">SplitView</a></p><p><strong>Input:</strong> <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>, <a href="/api/text-area" class="hover-link" data-tooltip="Multi-line text editing with cursor movement, selection, and word wrap">TextArea</a>, <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/command-palette" class="hover-link" data-tooltip="VS Code-style fuzzy command palette with keyboard navigation">CommandPalette</a>, <a href="/components/Form" class="hover-link" data-tooltip="Vertical form layout with labeled fields, validation, and submit handling">Form</a>, <a href="/components/Toggle" class="hover-link" data-tooltip="Boolean switch with label — keyboard-togglable on/off control">Toggle</a>, <a href="/components/SearchBar" class="hover-link" data-tooltip="Integrated search input — activates via / or Ctrl+F with match highlighting">SearchBar</a></p><p><strong>Display:</strong> <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a>, <a href="/components/Badge" class="hover-link" data-tooltip="Styled status label with variant colors (success, error, warning, primary)">Badge</a>, <a href="/api/spinner" class="hover-link" data-tooltip="Animated loading indicator with customizable frames">Spinner</a>, <a href="/api/progress-bar" class="hover-link" data-tooltip="Determinate/indeterminate progress indicator with theming">ProgressBar</a>, <a href="/api/table" class="hover-link" data-tooltip="Column-aligned table component with headers and auto-sizing">Table</a>, <a href="/api/tabs" class="hover-link" data-tooltip="Tabbed navigation component with keyboard support">Tabs</a>, <a href="/components/Toast" class="hover-link" data-tooltip="Auto-dismiss notification component">Toast</a>, Tooltip, <a href="/components/Skeleton" class="hover-link" data-tooltip="Placeholder loading indicator — animated shimmer effect for content not yet loaded">Skeleton</a>, Typography</p><p><strong>Navigation:</strong> <a href="/components/TreeView" class="hover-link" data-tooltip="Expandable/collapsible tree navigation component">TreeView</a>, <a href="/api/list-view" class="hover-link" data-tooltip="Virtualized list with pluggable cache, navigation, and search">ListView</a>, <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>, <a href="/components/Breadcrumb" class="hover-link" data-tooltip="Navigation breadcrumb trail with configurable separator">Breadcrumb</a></p><p><strong>Containers:</strong> <a href="/components/Screen" class="hover-link" data-tooltip="Root layout component — fills the terminal viewport with flexbox column layout">Screen</a>, <a href="/components/ModalDialog" class="hover-link" data-tooltip="Modal overlay with focus trapping and automatic theme">ModalDialog</a>, <a href="/components/PickerDialog" class="hover-link" data-tooltip="Modal selection dialog — fuzzy-searchable list with keyboard navigation">PickerDialog</a>, <a href="/components/ScrollbackView" class="hover-link" data-tooltip="Streaming content display for chat, logs, and agent output">ScrollbackView</a>, <a href="/components/ScrollbackList" class="hover-link" data-tooltip="Streaming list where completed items freeze into terminal scrollback">ScrollbackList</a>, <a href="/components/ErrorBoundary" class="hover-link" data-tooltip="Catches render errors in children and displays a fallback UI">ErrorBoundary</a>, <a href="/components/Console" class="hover-link" data-tooltip="Displays captured console.log/warn/error output inside the TUI">Console</a></p><p><strong>Interaction:</strong> Mouse events, spatial focus navigation (<code>focusScope</code> on <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>), command system with keybindings, input layer stack</p><p><strong>Theming:</strong> 38 palettes with semantic color tokens (<code>$primary</code>, <code>$success</code>, <code>$muted</code>, <code>$danger</code>), auto-detection of terminal background color, WCAG-aware contrast. See the <a href="/themes.html">theme explorer</a> to preview all palettes.</p><h2 id="terminal-protocol-coverage" tabindex="-1">Terminal Protocol Coverage <a class="header-anchor" href="#terminal-protocol-coverage" aria-label="Permalink to &quot;Terminal Protocol Coverage&quot;">​</a></h2><p>Silvery implements comprehensive terminal protocol support for cross-terminal compatibility and modern features:</p><p><strong>Styling:</strong> 16/256/truecolor SGR, bold, italic, dim, underline, strikethrough, inverse, extended underlines (curly, dotted, dashed) with underline color.</p><p><strong>Keyboard:</strong> Full <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a> (all 5 flags -- disambiguate, event types, alternate keys, all keys, associated text), press/repeat/release events, modifier detection including Super/Cmd.</p><p><strong>Mouse:</strong> X10, button event tracking, SGR extended protocol (coordinates beyond 223), focus in/out reporting, mouse cursor shape via OSC 22.</p><p><strong>Graphics:</strong> Kitty graphics protocol (PNG transmission with chunking), Sixel encoding with color quantization, automatic fallback (Kitty to Sixel to text placeholder).</p><p><strong>Clipboard &amp; Links:</strong> <a href="/guide/clipboard" class="hover-link" data-tooltip="Clipboard access escape sequence — copy/paste that works across SSH sessions.">OSC 52</a> clipboard access (works over SSH), <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Hyperlink escape sequence — makes text clickable in supporting terminals.">OSC 8</a> hyperlinks.</p><p><strong>Output:</strong> Synchronized output (<a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Synchronized output — terminal renders a frame atomically, preventing mid-frame tearing.">DEC mode 2026</a>) for flicker-free rendering, <a href="/guide/silvery-vs-ink#rendering" class="hover-link" data-tooltip="DEC private mode 1049 — a separate terminal buffer apps can take over (like vim). No scrollback, but full cell-level control. Also called alt-screen.">alternate screen</a> buffer, scroll regions (DECSTBM), cursor shape control (DECSCUSR).</p><p><strong>Queries:</strong> Cursor position (CPR), pixel dimensions (CSI 14t), text area size (CSI 18t), device attributes (DA1/DA2/DA3), terminal identification (XTVERSION). Used at startup for automatic capability detection.</p><p>For a feature-by-feature comparison with <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>, see the <a href="/guide/silvery-vs-ink.html#terminal-protocol-coverage">protocol tables in the detailed comparison</a>.</p><h2 id="what-else-comes-with-it" tabindex="-1">What Else Comes With It <a class="header-anchor" href="#what-else-comes-with-it" aria-label="Permalink to &quot;What Else Comes With It&quot;">​</a></h2><p>Beyond responsive layout, the renderer provides:</p><ul><li><strong>Atomic frame commit</strong> — every frame wrapped in <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Synchronized output — terminal renders a frame atomically, preventing mid-frame tearing.">DEC mode 2026</a> (<a href="/reference/terminal-protocols" class="hover-link" data-tooltip="DEC mode 2026 — wraps frame emission so the terminal paints atomically. Prevents tearing in tmux, Zellij, and other multiplexers.">synchronized output</a>). The terminal either sees old frame or new frame, never a half-drawn mixture. No flicker, no tearing, no component dropout during scroll.</li><li><strong>ANSI-aware cell compositing</strong> — proper style stacking, not just string concatenation</li><li><strong>Pure TypeScript</strong> — no <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>, no C++, no native dependencies. Runs on Node, Bun, and Deno</li><li><strong>Stable memory</strong> — normal JavaScript garbage collection, no <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> heap growth</li><li><strong>~99% <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 test compatibility</strong> — 918/931 tests pass. Existing <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> code works with minimal changes via the <code>silvery/ink</code> compatibility layer</li></ul><p>Optional packages extend the renderer into a full framework:</p><ul><li><strong>Rich interaction</strong> -- mouse events, spatial focus navigation, command system with keybindings, input layer stack</li><li><strong>Theming</strong> -- 38 palettes with semantic color tokens, auto-detects terminal colors</li><li><strong><span class="glossary-hint" data-tooltip="The Elm Architecture — (action, state) → [state, effects] pattern for structured interactive state">TEA</span> state machines</strong> (<code>@silvery/create</code>, optional) -- pure <code>(action, state) -&gt; [state, effects]</code> for testing, replay, and undo</li></ul><p>If you know React, you know Silvery -- the core API (<code>Box</code>, <code>Text</code>, <code>useInput</code>, <code>render</code>) is familiar. See the <a href="/getting-started/quick-start.html">getting started guide</a> to try it, or the <a href="/guide/silvery-vs-ink.html">detailed comparison</a> for the full technical breakdown.</p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><p>Ready to try Silvery? The <a href="/getting-started/quick-start.html">quick start guide</a> gets you from zero to a running terminal app in under 5 minutes. If you&#39;re migrating from <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>, see the <a href="/getting-started/migrate-from-ink.html">migration guide</a> -- most <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> code works with minimal changes.</p>`,48)])])}const g=t(o,[["render",n]]);export{m as __pageData,g as default};
